```class Solution {
public:
    int findMinimumOperations(string s1, string s2, string s3) {
        int i = s1.size() - 1, j = s2.size() - 1, k = s3.size() - 1, res = 0;
        while (i >= 0 && j >= 0 && k >= 0) {
            if (s1[i] == s2[j] && s2[j] == s3[k]) {
                i--; j--; k--;
            } else {
                if (s1[i] != s2[j]) {
                    if (s1[i] == s3[k]) res += j - k;
                    else res += i - k;
                } else {
                    if (s2[j] == s3[k]) res += i - k;
                    else res += j - k;
                }
                break;
            }
        }
        res += i + j + k;
        return res == s1.size() + s2.size() + s3.size() ? -1 : res;
    }
};
